window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q15"]=window.__LIBQ["tien-nghich"]["q15"]||{};window.__LIBQ["tien-nghich"]["q15"]["artifacts"]={"updatedAt":"2026-07-14","count":34,"artifacts":[{"id":"tam-giot-mau-tim","name":"Tám giọt máu tím","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"chua-dung-hop","blurb":"Thân thể con trai Diệp Mịch bị chém đôi hóa thành tám giọt máu tím, lao vào mi tâm Vương Lâm. Chưa dung hợp.","detail":"Sau khi Vương Lâm dùng huyết kiếm chém đôi con trai Diệp Mịch, thân thể đối phương hóa thành tám giọt máu màu tím, lần lượt chui vào mi tâm Vương Lâm. Vương Lâm không lập tức dung hợp.","congNang":["Tâm huyết biến hóa từ thân thể con trai Diệp Mịch, nhập vào mi tâm"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1580","denChuong":"","cachCoDuoc":"Thu từ thi thể con trai Diệp Mịch","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1580","loai":"xuất hiện","importance":"normal","giaiDoan":"Hóa thành từ con trai Diệp Mịch","text":"Con trai Diệp Mịch bị chém đôi, thân thể hóa tám giọt máu tím lao vào mi tâm Vương Lâm.","anchor":"hai nửa người hắn hóa thành tám giọt máu màu tím, lao về phía Vương Lâm lần lượt chui vào trong mi tâm của hắn"}]},"nguon":["@c1580"]},{"id":"dong-dan-chung","name":"Đông Đan chung","cn":"东丹钟","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Quy Nhất tông","soHuu":["Quy Nhất tông"],"trangThai":"dang-co","blurb":"Đông Đan chung là chí bảo của Quy Nhất tông, hình dáng chuông lớn ngàn trượng lơ lửng trên sân đại điện phân tông. Tại mốc @c1586, mũi huyết kiếm của Vương Lâm xuyên qua cửa đá phong ấn lộ ra ba tấc trên chuông, tỏa huyết quang kinh thiên.","detail":"Đông Đan chung là chí bảo trấn phái của Quy Nhất tông, mang hình dáng chiếc chuông khổng lồ ngàn trượng, tọa lạc lơ lửng trên sân đại điện phân tông, khí tượng trang nghiêm. Mã sư huynh từng sử dụng Đông Đan chung để kết nối thông đạo dẫn tới động phủ Thất Đạo Tông. Trong sự kiện tại @c1586, mũi huyết kiếm của Vương Lâm xuyên phá cửa đá phong ấn, lộ ra ba tấc trên thân chuông, phát ra huyết quang kinh thiên, gây chấn động.","hinhDang":"Chuông lớn ngàn trượng","nguonGoc":"Chí bảo Quy Nhất tông","congNang":["Kết nối thông đạo tới động phủ Thất Đạo Tông @c1586"],"chuSoHuu":[{"ten":"Quy Nhất tông","tuChuong":"@c1586","denChuong":"","cachCoDuoc":"Chí bảo tông phái","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1586","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Mũi huyết kiếm Vương Lâm xuyên qua phong ấn lộ ra trên Đông Đan chung, tỏa huyết quang kinh thiên. Chưởng môn phân tông nhận ra kiếm của Diệp Mịch.","anchor":"Chỉ thấy chiếc chuông lớn này tuôn ra một luồng huyết quang kinh thiên"}]},"dinhDanh":"goc","capNhatToi":"@c1586","nguon":["@c1586"]},{"id":"cua-da-phong-an","name":"Cửa đá phong ấn","cn":"","aliases":["lá phù phong ấn"],"category":"khac","categoryLabel":"Vật phẩm phong ấn","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Cánh cửa đá khổng lồ ở cuối thông đạo trong động phủ, có văn tự xa xưa và lá phù phong ấn hai chiều, bên kia thông ra Tiên Cương đại lục.","detail":"Cánh cửa đá bị ai đó nhét vào để chống đỡ thông đạo trường tồn vạn cổ. Trên cửa có lá phù tạo lực bài xích và uy áp, phong ấn hai chiều — ngoài không vào được, trong cũng không ra được. Có văn tự xa xưa chưa từng thấy, tỏa vẻ tang thương. Vương Lâm dùng lục đại bổn nguyên đâm huyết kiếm sâu ba thước vào cửa.","congNang":["Phong ấn hai chiều, chống đỡ thông đạo trường tồn @c1586"],"tabs":{"tienTrinh":[{"chuong":"@c1586","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm phát hiện và xuyên phá","text":"Vương Lâm phát hiện cửa đá ở cuối thông đạo, nhận ra phong ấn hai chiều, dùng huyết kiếm đâm sâu ba thước xuyên qua lá phù.","anchor":"Lá phù này có tác dụng phong ấn cánh cửa, khiến cho người bên ngoài không thể tiến vào, cũng không có cách nào đi ra khỏi cánh cửa"}]},"dinhDanh":"goc","capNhatToi":"@c1586","nguon":["@c1586"]},{"id":"ngoc-gian-vuong-lam-tu-do-nam","name":"Ngọc giản Vương Lâm giao Tư Đồ Nam","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tư Đồ Nam"],"trangThai":"da-dung","blurb":"Ngọc giản do Vương Lâm giao cho Tư Đồ Nam ba năm trước tại Chu Tước Tinh, bên trong phong ấn một tia thần thức của Vương Lâm. Khi viễn cổ tiên nhân xâm nhập tiên giới, Tư Đồ Nam bóp nát ngọc giản kích hoạt thần thức, huyễn hóa thân ảnh Vương Lâm phát sát lục kinh thiên đuổi hơn mười tiên nhân. Ngọc giản đã bị phá hủy sau khi sử dụng.","detail":"Ngọc giản này được Vương Lâm trao cho Tư Đồ Nam tại Chu Tước Tinh kèm lời dặn chỉ bóp nát khi tiên nhân giáng trần tàn sát giới nội. Ba năm sau, khi viễn cổ tiên nhân xâm nhập tiên giới, Tư Đồ Nam tuân theo lời dặn bóp nát ngọc giản. Thần thức Vương Lâm phong ấn bên trong lập tức tuôn ra, huyễn hóa thành thân ảnh của Vương Lâm và phát ra sát lục kinh thiên, đuổi hơn mười tiên nhân khỏi tiên giới. Ngọc giản là vật dùng một lần, sau khi kích hoạt đã hoàn toàn bị phá hủy.","congNang":["Chứa một tia thần thức Vương Lâm; khi bóp nát, thần thức tuôn ra huyễn hóa thành thân ảnh Vương Lâm @c1593","Thân ảnh huyễn hóa phát sát lục kinh thiên, đủ sức đuổi hơn mười viễn cổ tiên nhân khỏi tiên giới @c1593"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1593","denChuong":"@c1593","cachCoDuoc":"Tự tạo","trangThai":"da-giao"},{"ten":"Tư Đồ Nam","tuChuong":"@c1593","denChuong":"@c1593","cachCoDuoc":"Vương Lâm giao ở Chu Tước Tinh ba năm trước","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1593","loai":"dùng","importance":"major","giaiDoan":"Bóp nát kích hoạt","text":"Tư Đồ Nam bóp nát ngọc giản khi tiên nhân xâm nhập tiên giới, thần thức Vương Lâm huyễn hóa thân ảnh phát sát lục đuổi tiên nhân.","anchor":"Vương Lâm trước khi rời đi liền báo cho hắn vào ngày viễn cổ tiên nhân giáng trần, nếu dám tàn sát tu sĩ giới nội thì phải bóp nát ngọc giản này"}]},"nguon":["@c1593"],"uyLuc":"Sát lục phát ra từ thân ảnh huyễn hóa đủ sức trấn áp và xua đuổi hơn mười viễn cổ tiên nhân khỏi tiên giới @c1593","dacDiem":"Vật dùng một lần, bóp nát mới kích hoạt; sau khi sử dụng ngọc giản bị phá hủy hoàn toàn"},{"id":"ngu-thai-ho-diep","name":"Ngũ Thải hồ điệp","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"bi-huy","blurb":"Con bướm nhiều màu bay ra đậu trên vai Vương Lâm, đôi cánh vỗ rơi phấn màu đẹp mắt. Tham gia phòng ngự trước chưởng ấn huyền kiếp của Chưởng Tôn nhưng bị tiêu tan.","detail":"Ngũ Thải hồ điệp là một linh vật nhiều màu sắc của Vương Lâm. Khi chiến đấu, nó bay ra đậu trên vai chủ nhân, vỗ cánh rơi phấn màu. Trước chưởng ấn trăm trượng tu vi huyền kiếp của Chưởng Tôn, Ngũ Thải hồ điệp run lên hóa thành nhiều màu sắc rồi tiêu tan.","congNang":["Phòng thủ / hỗ trợ chiến đấu, vỗ cánh rơi phấn màu"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1595","denChuong":"","cachCoDuoc":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1595","loai":"dùng","importance":"normal","giaiDoan":"Triển khai và bị tiêu tan","text":"Vương Lâm triển khai Ngũ Thải hồ điệp đậu trên vai để phòng thủ trước Chưởng Tôn. Sau khi chưởng ấn trăm trượng huyền kiếp đánh tới, hồ điệp run lên hóa nhiều màu sắc rồi tiêu tan.","anchor":"Một con bướm nhiều màu vẫy cánh bay ra đậu trên vai Vương Lâm"}]},"nguon":["@c1595"]},{"id":"cot-chau-chuong-ton","name":"Cốt châu (Chưởng Tôn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Chưởng Tôn"],"trangThai":"dang-co","blurb":"Cốt châu trong đầu Chưởng Tôn, lớn cỡ nắm tay, tỏa ánh sáng xám chứa bạch cốt khí tức đậm đặc, bức ra có thể tăng tu vi và thần thông mấy lần.","detail":"Chưởng Tôn vỗ đầu bức ra cốt châu lớn cỡ nắm tay, tỏa ánh sáng màu xám cả vạn trượng, chứa bạch cốt khí tức đậm đặc, khiến tu vi và thần thông tăng mấy lần để quyết cược với Vương Lâm.","congNang":["Tăng tu vi và thần thông mấy lần khi bức ra"],"chuSoHuu":[{"ten":"Chưởng Tôn","tuChuong":"@c1596","denChuong":"","cachCoDuoc":"Bảo vật trong thân thể","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1596","loai":"dùng","importance":"normal","giaiDoan":"Bức ra quyết chiến","text":"Chưởng Tôn vỗ đầu bức ra cốt châu để tăng tu vi mấy lần quyết cược với mũi tên cung Lý Quảng của Vương Lâm, nhưng vẫn bị xuyên phá.","anchor":"Một cốt châu lớn cỡ nắm tay bị bức ra. Cốt châu này toả ánh sáng màu xám cả vạn trượng, lộ ra khí tức bạch cốt đậm đặc"}]},"nguon":["@c1596"]},{"id":"ngoc-gian-tao-hac-dong","name":"Ngọc giản tạo hắc động","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Ngọc giản do Phàn San Lộ đưa cho Vương Lâm từ trước, chứa năng lực tạo hắc động truyền tống tới nơi Phàn San Lộ ẩn náu. Khi bóp nát, ngọc giản sinh ra hắc động cỡ nắm tay có lực hút kinh thiên, sau đó vỡ nát tiêu tán, chỉ dùng được một lần.","detail":"Ngọc giản này được Phàn San Lộ trao cho Vương Lâm từ trước để dùng trong tình huống nguy cấp. Tại thời điểm đạo nhân bảy màu lộ diện trong tinh không Thái Cổ Tinh Thần, Vương Lâm bóp nát ngọc giản, lập tức xuất hiện một hắc động lớn cỡ nắm tay tỏa lực hút kinh thiên, mở đường truyền tống tới vị trí Phàn San Lộ đang ẩn náu. Từ bên trong hắc động, ngọc thủ của Phàn San Lộ vươn ra đỡ đòn cho Vương Lâm. Sau khi hoàn thành tác dụng, ngọc giản hóa thành vô số mảnh vỡ tiêu tán hoàn toàn, bản chất là vật dùng một lần.","congNang":["Bóp nát tạo ra hắc động cỡ nắm tay có lực hút kinh thiên, truyền tống người sử dụng tới vị trí Phàn San Lộ ẩn náu @c1597"],"chuSoHuu":[{"ten":"Phàn San Lộ","tuChuong":"@c1597","denChuong":"@c1597","cachCoDuoc":"Chế tạo/sở hữu ban đầu","trangThai":"da-cho-di"},{"ten":"Vương Lâm","tuChuong":"@c1597","denChuong":"@c1597","cachCoDuoc":"Được Phàn San Lộ đưa từ trước","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1597","loai":"dùng","importance":"major","giaiDoan":"Sử dụng thoát thân","text":"Vương Lâm bóp nát ngọc giản tạo hắc động thoát khỏi tinh không Thái Cổ Tinh Thần, ngọc giản hóa mảnh vỡ tiêu tán.","anchor":"Bóp mạnh một cái, ngọc giản liền hoá thành vô số mảnh vỡ tiêu tán"}]},"nguon":["@c1597"],"uyLuc":"Tạo hắc động có lực hút kinh thiên, mở đường truyền tống xuyên tinh không Thái Cổ Tinh Thần, đủ để thoát khỏi nguy cơ từ đạo nhân bảy màu.","dacDiem":"Vật dùng một lần, bóp nát liền phát động, sau khi sử dụng hóa thành vô số mảnh vỡ tiêu tán hoàn toàn."},{"id":"giot-huyet-mach-tien-nhan","name":"Giọt huyết mạch tiên nhân","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Giọt huyết mạch tiên nhân là vật phẩm do Hứa Lập Quốc và Lưu Kim Bưu lừa lấy từ người điên (Liên Đạo Phi), cuối cùng rơi vào tay Vương Lâm. Giọt huyết này được dùng làm nguồn lực bổ sung để kéo cung Lý Quảng, phát huy uy lực trong trận chiến quan trọng.","detail":"Giọt huyết mạch tiên nhân vốn thuộc về Liên Đạo Phi, bị Hứa Lập Quốc và Lưu Kim Bưu dùng thủ đoạn lừa lấy, sau đó lọt vào tay Vương Lâm. Vương Lâm giữ kín việc sở hữu giọt huyết này, khiến Chưởng Tôn không biết mà tính sai số lần Vương Lâm có thể kéo cung Lý Quảng. Tại @c1598, Vương Lâm dùng giọt huyết mạch tiên nhân để bổ sung lực lượng kéo cung Lý Quảng, bắn ra mũi tên va chạm với chín hỏa điểu của đạo nhân, thể hiện vai trò then chốt trong trận đấu.","nguonGoc":"Do Hứa Lập Quốc và Lưu Kim Bưu lừa từ người điên (Liên Đạo Phi)","congNang":["Bổ sung lực lượng để kéo cung Lý Quảng, cho phép Vương Lâm bắn thêm mũi tên ngoài dự tính của đối phương @c1598"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1598","denChuong":"","cachCoDuoc":"Thu được qua tay Hứa Lập Quốc và Lưu Kim Bưu","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1598","loai":"dùng","importance":"major","giaiDoan":"Vương Lâm sử dụng","text":"Vương Lâm dùng giọt huyết mạch tiên nhân để kéo cung Lý Quảng bắn mũi tên va chạm chín hỏa điểu của đạo nhân bảy màu. Chưởng Tôn không biết hắn còn giọt này nên tính sai.","anchor":"Nhưng Chưởng Tôn lại không biết là trong tay Vương Lâm còn có một giọt huyết mạch tiên nhân nữa"}]},"nguon":["@c1598"],"uyLuc":"Mũi tên bắn ra từ cung Lý Quảng nhờ giọt huyết mạch tiên nhân đủ sức va chạm với chín hỏa điểu của đạo nhân @c1598"},{"id":"chin-hoa-dieu","name":"Chín hỏa điểu","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Đạo nhân bảy màu"],"trangThai":"dang-co","blurb":"Chín con hỏa điểu màu đỏ do đạo nhân bảy màu triệu ra, thực chất là chín tu chân tinh cực hiếm bị luyện hóa.","detail":"Chín tu chân tinh trong động phủ bị đạo nhân bảy màu luyện hóa thành chín hỏa điểu. Uy lực nhiệt độ vượt cả Chu Tước, có khí tức hồn phách tu chân tinh. Tương đương chín mặt trời thiêu đốt.","congNang":["Tấn công bằng hỏa viêm uy lực vượt Chu Tước","Có khí tức hồn phách tu chân tinh"],"nguonGoc":"Chín tu chân tinh trong động phủ Vân Hải bị đạo nhân bảy màu luyện hóa","chuSoHuu":[{"ten":"Đạo nhân bảy màu","tuChuong":"@c1598","denChuong":"","cachCoDuoc":"Luyện hóa từ chín tu chân tinh","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1598","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Đạo nhân bảy màu triệu chín hỏa điểu tấn công Vương Lâm và Phàn San Lộ, bị mũi tên cung Lý Quảng và Dẫn Hồn Minh đối kháng.","anchor":"rõ ràng là chín tu chân tinh thiêu đốt cực kỳ hiếm thấy trong động phủ này bị đạo nhân bảy màu luyện hóa"}]},"nguon":["@c1598"]},{"id":"manh-vo-thai-co-than-canh","name":"Mảnh vỡ từ Thái Cổ Thần Cảnh","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Không rõ (bảo vật từ Thái Cổ Thần Cảnh)","soHuu":["Thất Thải Tiên Tôn"],"trangThai":"dang-co","blurb":"Mảnh vỡ của bảo vật không tên bay ra từ Thái Cổ Thần Cảnh khi mặt trời thứ chín xuất hiện, bên trong chứa thiên đạo ngày nay. Rơi vào tay Thất Thải Tiên Tôn nhờ cơ duyên xảo hợp, nhưng muốn mở ra cực kỳ gian nan.","detail":"Khi mặt trời thứ chín xuất hiện, một bảo vật bay ra từ Thái Cổ Thần Cảnh tại phụ cận Thất Đạo Tông, bị Đạo Nhất đại thiên tôn và Huyền La đại thiên tôn tranh đoạt. Trong cuộc tranh đoạt, một mảnh vỡ tách ra và nhờ cơ duyên xảo hợp rơi vào tay Thất Thải Tiên Tôn. Mảnh vỡ này muốn mở ra cực kỳ gian nan; Thất Thải Tiên Tôn phải dùng tu vi chiếm đoạt từ Phàn San Mộng để trấn áp và mở nó. Bên trong mảnh vỡ chứa thiên đạo ngày nay. Sự tồn tại của mảnh vỡ được Phàn San Mộng tiết lộ @c1599.","congNang":["Chứa thiên đạo ngày nay @c1599"],"nguonGoc":"Thái Cổ Thần Cảnh, bay ra khi mặt trời thứ chín xuất hiện","dacDiem":"Muốn mở ra cực kỳ gian nan, cần tu vi cực cao để trấn áp mới có thể khai mở.","chuSoHuu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1599","denChuong":"","cachCoDuoc":"Nhờ cơ duyên xảo hợp lấy được khi Đạo Nhất và Huyền La tranh đoạt","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1599","loai":"xuat-hien","importance":"major","giaiDoan":"Tiết lộ nguồn gốc và bí mật bên trong","text":"Phàn San Mộng tiết lộ: bảo vật bay ra từ Thái Cổ Thần Cảnh bị Đạo Nhất và Huyền La tranh đoạt, mảnh vỡ rơi vào tay Thất Thải Tiên Tôn. Bên trong chứa thiên đạo ngày nay.","anchor":"bên trong mảnh nhỏ là thiên đạo ngày nay"}]},"nguon":["@c1599"]},{"id":"thuyen-tim","name":"Thuyền tím","cn":"","aliases":["chiến thuyền cấm chế","chiếc thuyền cấm bảo Đại Hồn Môn","chiếc thuyền cổ của Phàn San Mộng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Trung phẩm cấm bảo","soHuu":["Phàn San Mộng","Vương Lâm"],"trangThai":"đang tranh quyền kiểm soát","blurb":"Thuyền tím là cấm bảo trung phẩm thuộc Đại Hồn Môn, boong tàu thực chất do cấm chế ngưng tụ mà thành với ký hiệu chi chít dày đặc có ô quang, phòng hộ nhiều lớp. Phàn San Mộng từng thách đố tặng thuyền cho Vương Lâm nếu hắn nghiên cứu ra toàn bộ cấm chế, và Vương Lâm đã lần lượt phá giải hàng ngàn vạn cấm chế trên thuyền.","detail":"Thuyền tím là cấm bảo trung phẩm của Đại Hồn Môn, bề ngoài mang sắc tím, kết cấu phức tạp với chín tầng cấm chế vừa bảo hộ vừa điều khiển thuyền. Boong tàu không phải vật chất thông thường mà do cấm chế ngưng tụ tạo thành, bề mặt phủ đầy ký hiệu cấm chế dày đặc phát ra ô quang. Tầng sáng phòng hộ nhiều lớp của thuyền có thể cầm cự khoảng ba ngày trước sức tấn công của Thất Thải Tiên Tôn. Tầng cuối cùng bên trong thuyền có tế đàn chứa cổ lực và truyền thừa của Đại Hồn Môn. Cánh buồm trên thuyền mang hình mặt quỷ, phát ra khí tức yêu dị. Phàn San Mộng đã thách đố Vương Lâm rằng nếu hắn nghiên cứu ra toàn bộ cấm chế thì sẽ tặng thuyền cho hắn. Tại @c1601, Phàn San Mộng tiết lộ thuyền là cấm bảo trung phẩm và Vương Lâm bắt đầu phá tầng phòng hộ cấm chế. Đến @c1602, Vương Lâm phá toàn bộ mấy ng","congNang":["Di chuyển, dùng làm phương tiện phi hành @c1601","Phòng hộ cường đại nhiều lớp, tầng sáng có thể cầm cự khoảng ba ngày trước tấn công của Thất Thải Tiên Tôn @c1601","Chín tầng cấm chế vừa bảo hộ vừa điều khiển thuyền, boong tàu do cấm chế ngưng tụ thành @c1601 @c1602","Cánh buồm mặt quỷ phát ra khí tức yêu dị","Tầng cuối chứa tế đàn có cổ lực và truyền thừa của Đại Hồn Môn"],"hinhDang":"Thuyền tím","nguonGoc":"Cấm bảo của Đại Hồn Môn","dacDiem":"Boong tàu do cấm chế ngưng tụ mà thành, ký hiệu cấm chế chi chít dày đặc phát ra ô quang, cánh buồm hình mặt quỷ tỏa khí tức yêu dị, nội bộ chia nhiều tầng với hàng ngàn vạn cấm chế.","chuHienThoi":"Phàn San Mộng","chuSoHuu":[{"ten":"Phàn San Mộng","tuChuong":"@c1599","denChuong":"","cachCoDuoc":"Sở hữu ban đầu","trangThai":"đang mất dần quyền kiểm soát"},{"ten":"Vương Lâm","tuChuong":"@c1602","denChuong":"","cachCoDuoc":"Phá cấm chế đoạt quyền điều khiển","trangThai":"đang đoạt dần"}],"tabs":{"tienTrinh":[{"chuong":"@c1601","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lộ bản chất cấm chế và phẩm cấp","text":"Phàn San Mộng tiết lộ thuyền là cấm bảo trung phẩm Đại Hồn Môn. Vương Lâm phá tầng phòng hộ cấm chế, phát hiện boong thuyền do cấm chế ngưng tụ thành, cấm chế bên ngoài bao la hàng vạn.","anchor":"Chiếc thuyền này là cấm bảo của Đại Hồn Môn chúng ta. Tuy rằng nó không phải là thượng phẩm nhưng cũng đạt tới trung phẩm."},{"chuong":"@c1602","loai":"khai phong","importance":"major","giaiDoan":"Vương Lâm phá hai tầng cấm chế đầu","phamCap":"Cấm bảo","text":"Vương Lâm phá toàn bộ mấy ngàn vạn cấm chế trên boong tàu (tầng một) rồi tiến xuống phá xong tầng hai trong bảy canh giờ. Đoạt phần lớn quyền điều khiển, Phàn San Mộng chỉ còn nhiều hơn một chút. Lộ ra thuyền có chín tầng cấm chế, cánh buồm mang mặt quỷ phát sáng yêu dị.","anchor":"Thuyền này có chín tầng cấm chế boong tàu là tầng thứ nhất, bên dưới còn tám tầng"}]},"capNhatToi":"@c1601","nguon":["@c1599","@c1601","@c1602"],"uyLuc":"Tầng phòng hộ nhiều lớp của thuyền có thể cầm cự khoảng ba ngày trước sức tấn công của Thất Thải Tiên Tôn."},{"id":"tam-buom-mat-quy","name":"Tấm buồm mặt quỷ","cn":"","aliases":["Cánh buồm có khuôn mặt quỷ","buồm mặt quỷ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cấm bảo","soHuu":["Vương Lâm"],"trangThai":"đang được luyện hóa","blurb":"Pháp bảo của Đại Hồn Môn, là chủ hồn trên chiếc thuyền tím cấm chế. Phàn San Mộng nương lực lượng của tấm buồm để thi triển Đại Hồn chân ảo thuật song trùng huyễn từ xa. Bị Vương Lâm thu làm bồi thường và luyện hóa, dần nắm được phương pháp điều khiển thuyền.","detail":"Tấm buồm mang khuôn mặt quỷ sống động dữ tợn, là pháp bảo thuộc Đại Hồn Môn, đóng vai trò chủ hồn trên chiếc thuyền tím cấm chế. Trên buồm chứa toàn bộ cấm chế của thuyền, là then chốt để vận hành và điều khiển con thuyền. Phàn San Mộng nương vào lực lượng của tấm buồm để thi triển Đại Hồn chân ảo thuật song trùng huyễn từ xa. Vương Lâm nhận ra vai trò then chốt của tấm buồm, tuyên bố thu nó cùng chiếc thuyền làm bồi thường cho việc bị lừa, thu vào không gian trữ vật và tiến hành luyện hóa, dần nắm được phương pháp điều khiển thuyền thông qua tấm buồm.","nguon":["@c1605"],"hinhDang":"Tấm buồm có khuôn mặt quỷ sống động dữ tợn","nguonGoc":"Pháp bảo của Đại Hồn Môn","congNang":["Là chủ hồn trên thuyền tím, then chốt vận hành con thuyền @c1605","Hỗ trợ thi triển Đại Hồn chân ảo thuật song trùng huyễn từ xa @c1605","Chứa toàn bộ cấm chế trên thuyền","Luyện hóa xong có thể điều khiển thuyền"],"chuSoHuu":[{"ten":"Đại Hồn Môn","tuChuong":"","denChuong":"@c1605","cachCoDuoc":"Pháp bảo gốc của môn phái","trangThai":"đã mất"},{"ten":"Vương Lâm","tuChuong":"@c1605","denChuong":"","cachCoDuoc":"Thu làm bồi thường sau khi bị lừa bởi ảo thuật","trangThai":"đang luyện hóa"}],"capNhatToi":"@c1605","tabs":{"tienTrinh":[{"chuong":"@c1605","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm thu làm bồi thường","text":"Vương Lâm nhận ra tấm buồm là chủ hồn trên thuyền và phương tiện then chốt giúp Phàn San Mộng thi triển ảo thuật từ xa. Tuyên bố thu buồm và thuyền làm bồi thường, thu vào không gian trữ vật bắt đầu luyện hóa, dần nắm phương pháp điều khiển thuyền.","anchor":"Đây là pháp bảo của Đại Hồn Môn chúng ta, cũng chính là chủ hồn trên chiếc thuyền này"}]}},{"id":"ngoc-gian-ban-do-te-dan","name":"Ngọc giản bản đồ tế đàn","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Ngọc giản do Phàn San Lộ trao cho Vương Lâm, chứa bản đồ dẫn tới tế đàn trong không gian vết rách và thuật thôn hồn người thứ ba.","detail":"Phàn San Lộ trao ngọc giản này cho Vương Lâm, bên trong chứa bản đồ chỉ đường tới tế đàn nằm trong không gian vết rách của động phủ Thất Thải Tiên Tôn, đồng thời chứa thuật thần thông thôn hồn người thứ ba.","nguon":["@c1605"],"congNang":["Chứa bản đồ dẫn tới tế đàn","Chứa thuật thôn hồn người thứ ba"],"chuSoHuu":[{"ten":"Phàn San Lộ","tuChuong":"","denChuong":"@c1605","cachCoDuoc":"Sở hữu ban đầu","trangThai":"đã trao"},{"ten":"Vương Lâm","tuChuong":"@c1605","denChuong":"","cachCoDuoc":"Phàn San Lộ trao","trangThai":"đang sử dụng"}],"capNhatToi":"@c1605","tabs":{"tienTrinh":[{"chuong":"@c1605","loai":"đổi chủ","importance":"normal","giaiDoan":"Phàn San Lộ trao cho Vương Lâm","text":"Phàn San Lộ trao ngọc giản chứa bản đồ tế đàn và thuật thôn hồn người thứ ba cho Vương Lâm.","anchor":"Một ngọc giản bay ra tiến về phía Vương Lâm, bị hắn bắt lấy"}]}},{"id":"the-huyet-phan-san-lo","name":"Thệ huyết Phàn San Lộ","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"đã dung nhập","blurb":"Thệ huyết do Phàn San Lộ cắn lưỡi phun ra, máu đỏ chuyển vàng nhạt, Vương Lâm nhận và dung nhập vào cơ thể.","detail":"Phàn San Lộ cắn lưỡi phun máu tươi, máu tỏa ánh đỏ đậm rồi chuyển sang màu vàng nhạt khi thành thệ huyết, bay tới Vương Lâm. Hắn nhận và dung nhập vào cơ thể, hoàn tất cam kết.","nguon":["@c1605"],"dacDiem":"Máu đỏ chuyển vàng nhạt khi thành thệ huyết","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1605","denChuong":"","cachCoDuoc":"Phàn San Lộ phun thệ huyết trao","trangThai":"đã dung nhập"}],"capNhatToi":"@c1605","tabs":{"tienTrinh":[{"chuong":"@c1605","loai":"xuất hiện","importance":"normal","giaiDoan":"Phàn San Lộ trao thệ huyết","text":"Phàn San Lộ cắn lưỡi phun thệ huyết, máu đỏ chuyển vàng, Vương Lâm nhận dung nhập vào cơ thể.","anchor":"Đây là thệ huyết của ta"}]}},{"id":"chin-mat-troi","name":"Chín mặt trời","cn":"九日","aliases":["cửu nhật"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thất Thải Tiên Tôn"],"trangThai":"dang-co","blurb":"Pháp bảo của Thất Thải Tiên Tôn: chín quang cầu to bằng nắm tay lơ lửng bên ngoài thân, bên trong mỗi quang cầu chứa một con hỏa điểu.","detail":"Chín quang cầu to bằng nắm tay lơ lửng bên ngoài thân đạo nhân bảy màu trong huyễn cảnh, mỗi quang cầu chứa một con hỏa điểu. Công năng cụ thể chưa rõ.","congNang":["Chứa chín con hỏa điểu trong chín quang cầu"],"chuSoHuu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1606","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1606","loai":"xuat-hien","importance":"normal","giaiDoan":"Lộ diện trong huyễn cảnh","text":"Chín quang cầu chứa hỏa điểu lơ lửng bên ngoài thân đạo nhân bảy màu khi ngồi thẫn thờ trên đỉnh núi trong huyễn cảnh.","anchor":"Ở bên ngoài thân thể hắn có chín quang cầu to bằng nắm tay đang lơ lửng, bên trong có chín con hỏa điểu"}]},"nguon":["@c1606"]},{"id":"manh-vo-bi-an-tien-ton","name":"Mảnh vỡ (Thất Thải Tiên Tôn đạt được)","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Thất Thải Tiên Tôn"],"trangThai":"khong-ro","blurb":"Mảnh vỡ bí ẩn mà Thất Thải Tiên Tôn đạt được, là nguyên nhân cốt lõi dẫn tới đại chiến khi nhiều cường giả tranh đoạt. Liên Đạo Phi và Phàn San Mộng đều muốn chiếm lấy vật phẩm này.","detail":"Bản chất và nguồn gốc của mảnh vỡ vẫn chưa được tiết lộ. Liên Đạo Phi tuyên bố rằng mục đích duy nhất khiến hắn tới nơi là vì mảnh vỡ mà Thất Thải Tiên Tôn đạt được, và sẵn sàng rời đi nếu được giao lại (@c1606). Thất Thải Tiên Tôn chất vấn liệu chỉ vì một mảnh nhỏ đó mà các bên quên đi nghĩa tình mấy ngàn năm. Mảnh vỡ có giá trị đủ lớn để khiến nhiều cường giả bất chấp tình nghĩa, sẵn sàng khai chiến.","congNang":["Chưa rõ — được nhiều cường giả tranh đoạt"],"chuSoHuu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1606","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"khong-ro"}],"tabs":{"tienTrinh":[{"chuong":"@c1606","loai":"xuat-hien","importance":"major","giaiDoan":"Nguyên nhân đại chiến lộ diện","text":"Liên Đạo Phi tuyên bố chỉ vì mảnh vỡ mà Tiên Tôn đạt được mà tới, sẵn sàng rời nếu được giao. Thất Thải Tiên Tôn chất vấn liệu vì mảnh nhỏ đó mà các kẻ phản bội quên nghĩa mấy ngàn năm.","anchor":"Ta tới đây chỉ vì mảnh vỡ mà ngươi đạt được"}]},"nguon":["@c1606"],"dacDiem":"Vật phẩm có giá trị cực cao, đủ khiến nhiều cường giả như Liên Đạo Phi, Phàn San Mộng tranh đoạt bất chấp nghĩa tình ngàn năm (@c1606)."},{"id":"canh-tay-dao-co-te-dan","name":"Cánh tay Đạo Cổ trên tế đàn","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"Không rõ","soHuu":[],"trangThai":"cố định trên tế đàn","blurb":"Cánh tay kích thước mười trượng nằm ở trung tâm trận pháp tang thương trên đỉnh tế đàn bát giác trong khe Vân Hải tinh vực, tỏa khí tức Đạo Cổ, an tĩnh bất động. Là mục tiêu sinh cơ mà Vương Lâm hướng tới sau khi bói toán.","detail":"Cánh tay này nằm ở trung tâm trận pháp tang thương, đồng thời cũng là trung tâm của tế đàn bát giác. Kích thước đạt mười trượng, thường xuyên tỏa ra khí tức Đạo Cổ và giữ trạng thái an tĩnh bất động. Tế đàn nơi cánh tay tọa lạc hình thành từ sự kiện thiên đạo cắn nuốt Liên Đạo Phi và Thất Thải Tiên Tôn tan xác, do đó cánh tay có khả năng liên quan đến Thất Thải Tiên Tôn hoặc Liên Đạo Phi. Vương Lâm sau khi bói toán đã xác định đây là mục tiêu sinh cơ và hướng tới nơi này.","nguon":["@c1608"],"hinhDang":"Cánh tay, mười trượng","dacDiem":"Tỏa khí tức Đạo Cổ, an tĩnh bất động","congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c1608","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ lần đầu","text":"Cánh tay mười trượng tỏa khí Đạo Cổ nằm ở trung tâm trận pháp tang thương trên tế đàn được miêu tả khi Vương Lâm xác định tế đàn là sinh cơ.","anchor":"Trong trung tâm của trận pháp này, cũng là trung tâm của tế đàn có một cánh tay!"}]}},{"id":"chiec-thuyen-dai-hon-mon","name":"Chiếc thuyền Đại Hồn Môn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cấm bảo trung phẩm","soHuu":["Phàn San Mộng"],"trangThai":"dang-bi-nghien-cuu-cam-che","blurb":"Chiếc thuyền là cấm bảo trung phẩm của Đại Hồn Môn, do Phàn San Mộng điều khiển. Boong tàu bản chất là cấm chế ngưng tụ mà thành, bên ngoài có tầng phòng hộ cấm chế bao la hàng vạn hàng nghìn, bên trong tầng cuối chứa tế đàn có cổ lực.","detail":"Chiếc thuyền do Đại Hồn Môn chế tạo, đạt phẩm cấp cấm bảo trung phẩm, được Phàn San Mộng điều khiển sử dụng. Kết cấu thuyền đặc thù: boong tàu không phải vật liệu thông thường mà do cấm chế ngưng tụ mà thành, bên ngoài bao phủ tầng phòng hộ cấm chế bao la hàng vạn hàng nghìn lớp. Tầng cuối cùng của thuyền chứa một tế đàn có cổ lực. Vương Lâm từng phá được tầng phòng hộ ngoài cùng, khiến bản chất cấm chế của boong tàu lộ ra, rồi bắt đầu phân tích các cấm chế bên trong. Phàn San Mộng tuyên bố nếu Vương Lâm nghiên cứu ra toàn bộ cấm chế trên thuyền thì sẽ tặng luôn chiếc thuyền cho hắn.","phanLoaiPhu":"Cấm bảo","nguonGoc":"Đại Hồn Môn chế tạo","congNang":["Phòng hộ nhiều tầng cấm chế bao la hàng vạn hàng nghìn lớp bên ngoài boong tàu @c1601","Chứa tế đàn có cổ lực ở tầng cuối cùng của thuyền"],"dacDiem":"Boong tàu do cấm chế ngưng tụ mà thành, không phải vật liệu thông thường; tầng phòng hộ bên ngoài bao la hàng vạn hàng nghìn lớp cấm chế.","chuHienThoi":"Phàn San Mộng","chuSoHuu":[{"ten":"Phàn San Mộng","tuChuong":"@c1601","denChuong":"","cachCoDuoc":"Pháp bảo của Đại Hồn Môn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1601","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ bản chất cấm chế","phamCap":"Cấm bảo trung phẩm","text":"Vương Lâm phá tầng phòng hộ ngoài cùng boong thuyền, lộ ra bản chất boong tàu là cấm chế ngưng tụ mà thành. Bắt đầu phân tích cấm chế bên trong, Phàn San Mộng tuyên bố tặng thuyền nếu hắn thành công.","anchor":"Chiếc thuyền này là cấm bảo của Đại Hồn Môn chúng ta. Tuy rằng nó không phải là thượng phẩm nhưng cũng đạt tới trung phẩm"}]},"nguon":["@c1601"]},{"id":"te-dan-tren-thuyen","name":"Tế đàn trên thuyền","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Phàn San Mộng"],"trangThai":"chua-mo","blurb":"Tế đàn nằm ở tầng cuối chiếc thuyền Đại Hồn Môn, chứa cổ lực, do muội muội Phàn San Mộng vô ý đạt được.","detail":"Tế đàn nằm ở tầng cuối thuyền, bên trong có một luồng cổ lực mà tu vi của Phàn San Mộng không đủ phá vỡ. Nàng đề nghị Vương Lâm dùng ba ngày đến phá phòng hộ hấp thu truyền thừa bên trong để tăng tu vi, nhưng Vương Lâm từ chối.","congNang":["Chứa cổ lực, có thể tăng tu vi nếu hấp thu truyền thừa bên trong"],"tabs":{"tienTrinh":[{"chuong":"@c1601","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Phàn San Mộng tiết lộ","text":"Phàn San Mộng tiết lộ tế đàn chứa cổ lực ở tầng cuối thuyền, đề nghị Vương Lâm phá phòng hộ hấp thu truyền thừa.","anchor":"Trên tế đàn đó có một luồng cổ lực, với tu vi của nàng không thể phá vỡ"}]},"nguon":["@c1601"]},{"id":"canh-tay-dao-co-diep-mich","name":"Cánh tay Đạo Cổ Diệp Mịch","cn":"","category":"khac","categoryLabel":"Di thể Đạo Cổ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dung hợp","blurb":"Cánh tay bị cắt rời của Đạo Cổ Diệp Mịch, đặt trên tế đàn trong khe Vân Hải tinh vực. Phát khí tức Đạo Cổ, chỉ người mang truyền thừa chính tông Đạo Cổ mới có thể dung hợp; Vương Lâm nhận ra và dung hợp nó khi bị đạo nhân bảy màu truy kích.","detail":"Cánh tay này nằm trên tế đàn Đạo Cổ bên trong khe Vân Hải tinh vực. Khi Vương Lâm bị đạo nhân bảy màu truy kích đến tuyệt lộ, hắn phát hiện tế đàn và nhận ra cánh tay thuộc về Đạo Cổ Diệp Mịch nhờ khí tức Đạo Cổ tỏa ra từ nó. Coi đây là sinh cơ duy nhất, Vương Lâm đặt tay lên dung hợp; nhờ mang truyền thừa chính tông Đạo Cổ, cánh tay lập tức phát ra ánh sáng vạn trượng bao phủ toàn thân hắn.","congNang":["Phát ra khí tức Đạo Cổ @c1609","Khi dung hợp với người có truyền thừa chính tông Đạo Cổ, phát ánh sáng vạn trượng bao phủ toàn thân người đó @c1609"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1609","denChuong":"","cachCoDuoc":"Dung hợp trên tế đàn nhờ truyền thừa Đạo Cổ","trangThai":"đang dung hợp"}],"tabs":{"tienTrinh":[{"chuong":"@c1609","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm dung hợp","text":"Vương Lâm bị truy kích tới tế đàn, nhận ra cánh tay thuộc Đạo Cổ Diệp Mịch nhờ khí tức Đạo Cổ. Đặt tay lên dung hợp, cánh tay phát ánh sáng vạn trượng bao phủ toàn thân.","anchor":"Khí tức Đạo Cổ do cánh tay đó phát ra khiến Vương Lâm liếc mắt một cái là nhận ra cánh tay này là của Đạo cổ Diệp Mịch"}]},"nguon":["@c1609"],"dacDiem":"Là bộ phận thân thể bị cắt rời của Đạo Cổ Diệp Mịch, mang khí tức Đạo Cổ đặc trưng; chỉ người sở hữu truyền thừa chính tông Đạo Cổ mới đủ tư cách dung hợp."},{"id":"tam-giot-mau-dao-co","name":"Tám giọt máu Đạo cổ (Diệp Mịch)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Tám giọt máu tươi mang Đạo cổ lực tinh thuần do Đạo cổ Diệp Mịch để lại, được Vương Lâm hấp thu toàn bộ để đồng thời đột phá Bát Tinh Cổ Thần, Cổ Yêu và Cổ Ma.","detail":"Đây là tám giọt máu của Đạo cổ Diệp Mịch, bên trong chứa Đạo cổ lực tinh thuần. Vương Lâm lần lượt bóp nát từng giọt thành huyết vụ rồi hút vào cơ thể qua thất khiếu và lỗ chân lông. Giọt đầu tiên mất bảy ngày để hấp thu hoàn toàn; sau đó hắn bóp hai giọt cùng lúc, và cuối cùng bóp nát cả năm giọt còn lại. Toàn bộ quá trình kéo dài hơn mười ngày. Tám giọt máu đã tiêu hao hoàn toàn, cung cấp đủ Đạo cổ lực giúp Vương Lâm đồng thời đột phá cảnh giới Bát Tinh của cả ba tộc cổ — Cổ Thần, Cổ Yêu và Cổ Ma.","congNang":["Dung hợp Đạo cổ lực tinh thuần vào cơ thể người hấp thu, giúp đột phá Bát Tinh Cổ Thần, Cổ Yêu, Cổ Ma đồng thời @c1610"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1610","denChuong":"@c1610","cachCoDuoc":"Thu được từ cánh tay Đạo cổ Diệp Mịch","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1610","loai":"dùng","importance":"major","giaiDoan":"Hấp thu toàn bộ","text":"Vương Lâm bóp nát lần lượt tám giọt máu Đạo cổ, hút huyết vụ qua thất khiếu và lỗ chân lông suốt hơn mười ngày, tiêu hao toàn bộ để đột phá Bát Tinh.","anchor":"Tám giọt máu tươi của Diệp Mịch liền đồng loạt bay ra"}]},"nguon":["@c1610"],"dacDiem":"Bóp nát thành huyết vụ, hút vào cơ thể qua thất khiếu và lỗ chân lông; tiêu hao hoàn toàn sau khi hấp thu."},{"id":"yeu-giap-tim-do","name":"Yêu giáp tím đỏ","cn":"","category":"phap-bao","categoryLabel":"Giáp bảo","phamCap":"Bát tinh Cổ Yêu","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Bộ giáp ngưng tụ từ yêu khí khi Cổ Yêu đạt bát tinh, phủ toàn thân Vương Lâm. Phải tới bát tinh mới có thể ngưng tụ thành.","detail":"Tấm giáp hình thành từ yêu khí khi tám yêu tinh trong mắt trái dung hòa, Cổ Yêu đạt bát tinh. Trong Cổ Yêu tộc phải tới bát tinh mới có thể ngưng tụ thành bộ giáp này. Phủ toàn thân, màu tím đỏ.","congNang":["Giáp bảo phòng ngự bát tinh Cổ Yêu"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1611","denChuong":"","cachCoDuoc":"Tự ngưng tụ khi đạt bát tinh Cổ Yêu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1611","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngưng tụ lần đầu khi Cổ Yêu đạt bát tinh","text":"Yêu giáp tím đỏ ngưng tụ khi Vương Lâm vượt nhị tổn tứ kiếp Cổ Yêu, đạt bát tinh.","anchor":"Tấm áo giáp này trong Cổ Yêu tộc phải tới khi đạt tới bát tinh mới có thể ngưng tụ thành!"}]},"nguon":["@c1611"]},{"id":"ma-giap-den","name":"Ma giáp đen","cn":"","category":"phap-bao","categoryLabel":"Giáp bảo","phamCap":"Bát tinh Cổ Ma","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Bộ giáp đen như mực xuất hiện khi ma tinh hiện ra thay thế yêu giáp, phối hợp với tóc bạc tạo hình ảnh đen trắng.","detail":"Bộ giáp đen như mực xuất hiện khi tám ma tinh mắt phải hiện ra, ma khí thay thế yêu khí, yêu giáp tán đi. Phối hợp với mái tóc bạc tạo hình ảnh đen trắng phân minh.","congNang":["Giáp bảo phòng ngự bát tinh Cổ Ma"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1611","denChuong":"","cachCoDuoc":"Tự hình thành khi đạt bát tinh Cổ Ma","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1611","loai":"xuất hiện","importance":"normal","giaiDoan":"Hình thành lần đầu khi Cổ Ma đạt bát tinh","text":"Ma giáp đen xuất hiện khi Vương Lâm vượt nhị tổn tứ kiếp Cổ Ma, ma tinh thay thế yêu tinh.","anchor":"trên người xuất hiện một bộ giáp đen như mực"}]},"nguon":["@c1611"]},{"id":"hon-huyet-co-to","name":"Hồn huyết cổ tổ","cn":"","category":"khac","categoryLabel":"Huyết mạch","phamCap":"Siêu việt huyết mạch cổ thường","soHuu":["Vương Lâm"],"trangThai":"Vừa xuất hiện","blurb":"Giọt hồn huyết thứ mười màu tím do cổ tổ ban cho Vương Lâm sau khi hắn thách thức và chứng minh truyền thừa Cổ Thần, là hồn huyết cổ tổ chưa từng có tiền lệ — từ cổ chí kim chỉ tồn tại chín giọt hồn huyết, ba giọt tạo thành một tộc cổ. Sự xuất hiện của giọt thứ mười khiến cả Huyền La Đại Thiên Tôn lẫn hoàng tôn đều rung động khiếp sợ.","detail":"Trong tiến trình Vương Lâm chứng minh truyền thừa Cổ Thần trước cổ tổ, sau chín giọt máu đỏ thông thường, giọt thứ mười ngưng tụ mang sắc tím hoàn toàn khác biệt — đây là hồn huyết cổ tổ, bản chất siêu việt hẳn huyết mạch cổ thường. Từ cổ chí kim chỉ có chín giọt hồn huyết tồn tại, cứ ba giọt tạo thành một tộc cổ, chín giọt tạo nên tam mạch cổ hiện nay. Giọt thứ mười này là điều chưa có tiền lệ trong lịch sử, sự xuất hiện của nó khiến Huyền La Đại Thiên Tôn phải tự hỏi cổ tổ đưa ra hồn huyết liệu có ngụ ý gì bên trong, đồng thời hoàng tôn cũng vì đó mà rung động khiếp sợ. Ý nghĩa cụ thể và công dụng thực chiến của giọt hồn huyết cổ tổ này tính đến mốc hiện tại chưa được hé lộ rõ ràng.","phanLoaiPhu":"hồn huyết","hinhDang":"Giọt máu màu tím","nguonGoc":"Cổ tổ ban cho Vương Lâm sau khi hắn thách thức và chứng minh truyền thừa Cổ Thần","dacDiem":"Màu tím, khác biệt hoàn toàn với chín giọt hồn huyết đỏ thường; là giọt thứ mười chưa từng có tiền lệ từ cổ chí kim, do cổ tổ trực tiếp ban cho.","chuHienThoi":"Vương Lâm","congNang":["Bản chất là hồn huyết cổ tổ, siêu việt hoàn toàn so với huyết mạch cổ thường @c1614"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1614","denChuong":"","cachCoDuoc":"Cổ tổ chủ động ban cho sau khi bị thách thức","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1614","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","phamCap":"Siêu việt huyết mạch cổ thường","text":"Sau chín giọt máu đỏ, giọt thứ mười màu tím ngưng tụ — hồn huyết cổ tổ chưa từng có tiền lệ. Huyền La Đại Thiên Tôn lập tức phong bế tin tức.","anchor":"cổ tổ hồn huyết! Đây.đây là hồn huyết! Chuyện này không thể nào không có khả năng"}]},"nguon":["@c1614"]},{"id":"chin-giot-mau-tuoi-co-to","name":"Chín giọt máu tươi cổ tổ","cn":"","category":"khac","categoryLabel":"Huyết mạch","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"Đang sở hữu","blurb":"Chín giọt máu đỏ cổ tổ ngưng tụ từ mi tâm pho tượng chống trời, vượt xa tiền lệ bốn giọt trước đó.","detail":"Sau khi Vương Lâm thách thức cổ tổ, dòng xoáy hồi đáp: giọt máu tiếp tục ngưng tụ từ thứ năm tới thứ chín. Mỗi giọt ngưng tụ từ huyết quang mi tâm pho tượng chống trời trên thành trì Đạo cổ nhất mạch. Từ cổ chí kim mỗi lần Cổ Mạch Thương Khung Huyết đưa ra máu đều chấm dứt ở bốn giọt, chín giọt là chưa từng có.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1614","denChuong":"","cachCoDuoc":"Cổ tổ ban cho sau khi bị thách thức","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1614","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngưng tụ giọt 5-9","text":"Dòng xoáy hồi đáp Vương Lâm, giọt máu tiếp tục ngưng tụ từ thứ năm tới thứ chín, vượt xa tiền lệ bốn giọt.","anchor":"Từ cổ chí kim, cổ Mạch Thương Khung Huyết này mỗi lần sau khi đưa ra hết máu đều chấm dứt"}]},"nguon":["@c1614"]},{"id":"hat-chau-do-hon-phach","name":"Hạt châu đỏ (chứa hồn phách nữ tử)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cổ Hoàng"],"trangThai":"dang-dung","blurb":"Hạt châu màu đỏ to cỡ nắm tay, bên trong sương mù che phủ phân hồn một nữ tử ngồi khoanh chân. Do quốc sư Đạo cổ dung nhập tâm thần vào u minh, mang phân hồn từ nơi kỳ dị có tồn tại thiên đạo đặt vào, kèm lời tiên tri rằng nữ tử này sẽ giúp hoàng tôn thống nhất cổ quốc hoặc dẫn tới tử vong.","detail":"Hạt châu màu đỏ to cỡ nắm tay, bên trong có sương mù chuyển động che phủ hồn phách (phân hồn) một nữ tử bí ẩn. Quốc sư nước Đạo cổ dung nhập tâm thần vào u minh, mang phân hồn này từ một nơi kỳ dị có tồn tại thiên đạo rồi đặt vào hạt châu. Quốc sư đưa ra lời tiên tri mang tính hai mặt: nữ tử trong châu hoặc sẽ giúp hoàng tôn Đạo cổ thống nhất cổ quốc, hoặc sẽ dẫn tới cái chết của hoàng tôn. Sương mù bên trong châu che khuất tướng mạo nữ tử, và hồn phách của nàng không đầy đủ — chỉ là phân hồn chứ không phải toàn hồn. Hoàng tôn Đạo cổ sau đó triệu Diệp Đạo đến hỏi về việc tìm thân xác cho nữ tử này (@c1615).","congNang":["Chứa và bảo tồn phân hồn nữ tử bí ẩn được mang về từ nơi kỳ dị có tồn tại thiên đạo (@c1615)"],"dacDiem":"Hạt châu màu đỏ to cỡ nắm tay, bên trong sương mù chuyển động che phủ tướng mạo nữ tử; hồn phách bên trong không đầy đủ, chỉ là phân hồn.","nguonGoc":"Do quốc sư Đạo cổ mang phân hồn từ nơi kỳ dị có tồn tại thiên đạo","chuSoHuu":[{"ten":"Cổ Hoàng","tuChuong":"@c1615","denChuong":"","cachCoDuoc":"Quốc sư giao cho","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1615","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ diện trong tay hoàng tôn Đạo cổ","text":"Hoàng tôn Đạo cổ triệu Diệp Đạo hỏi về việc tìm nữ tử trong hạt châu. Quốc sư tiên tri hai kết cục: hoàng tôn thống nhất cổ quốc hoặc tử vong, cả hai có người tóc bạc. Sương mù hé mở tướng mạo nhưng bị ngón tay hoàng tôn che mất.","anchor":"Trên tay hắn lập tắc xuất hiện một hạt châu màu đỏ to cỡ nắm tay"}]},"capNhatToi":"@c1615","nguon":["@c1615"]},{"id":"hon-huyet-mau-tim","name":"Hồn huyết màu tím (giọt thứ mười)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Siêu cấp truyền thuyết","soHuu":["Vương Lâm"],"trangThai":"dang-dung","blurb":"Giọt hồn huyết thứ mười của cổ quốc, xuất hiện từ tam tổn đệ nhất kiếp Cổ Mạch Thương Khung Huyết mà Vương Lâm trải qua. Vạn đời cổ quốc chỉ có chín giọt hồn huyết, giọt thứ mười là sự kiện chấn động chưa từng có tiền lệ.","detail":"Hồn huyết màu tím là sản vật sinh ra khi Vương Lâm trải qua tam tổn đệ nhất kiếp Cổ Mạch Thương Khung Huyết. Giọt hồn huyết này xuất hiện từ mi tâm pho tượng cổ tổ, lơ lửng rồi bay vào dòng xoáy khổng lồ trước sự chứng kiến của gần trăm vạn tộc nhân. Trong lịch sử cổ quốc, tổng cộng chỉ từng tồn tại chín giọt hồn huyết, cứ ba giọt hợp lại thành một mạch cổ tộc, tạo nên ba mạch cổ tộc. Sự xuất hiện của giọt thứ mười mang ý nghĩa chấn động — nó mở ra khả năng hình thành mạch cổ tộc thứ tư nếu đạt thêm giọt hồn huyết nữa. Giọt hồn huyết tỏa màu tím yêu dị, khiến tâm thần người chứng kiến rung động.","congNang":["Cấu thành mạch cổ tộc — cứ ba giọt hồn huyết hợp lại thành một mạch cổ tộc @c1615","Giọt thứ mười nếu có thêm giọt hồn huyết nữa có thể tạo mạch cổ tộc thứ tư @c1615"],"dacDiem":"Tỏa màu tím yêu dị, khiến tâm thần rung động; xuất hiện từ mi tâm pho tượng cổ tổ rồi bay vào dòng xoáy khổng lồ.","nguonGoc":"Kết quả tam tổn đệ nhất kiếp Cổ Mạch Thương Khung Huyết của Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1615","denChuong":"","cachCoDuoc":"Đạt được từ tam tổn đệ nhất kiếp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1615","loai":"xuat-hien","importance":"major","giaiDoan":"Xuất hiện từ tam tổn đệ nhất kiếp","text":"Giọt hồn huyết thứ mười xuất hiện từ mi tâm pho tượng cổ tổ, bay vào dòng xoáy. Gần trăm vạn tộc nhân chứng kiến, kinh hoàng vì vạn đời chỉ có chín giọt.","anchor":"Vạn đời cổ quốc ta cũng chỉ có chín giọt mà thôi!"}]},"capNhatToi":"@c1615","nguon":["@c1615"]},{"id":"te-dan-phong-diet-toc-phan-ba","name":"Tế đàn Phong Diệt Tộc (phần thứ ba)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Phần tế đàn thứ ba và cuối cùng của Phong Diệt Tộc, hình bát giác tỏa hồng quang chói mắt giống huyết trì, ẩn giấu bên trong tế đàn đá nơi cúng tế cánh tay Diệp Mịch. Gom đủ phần này cùng hai phần trước là điều kiện để tu luyện Tam Mệnh Thuật.","detail":"Vật hình bát giác tỏa hồng quang chói mắt, mang khí tức Phong Diệt Tộc giống hệt huyết các Huyết Tổ. Ẩn trong một cái khe sâu bên trong tế đàn đá, được bảo vệ bởi hồng vân có khả năng tiêu diệt cấm chế như thiên địch — tuyết gặp lửa. Vương Lâm dùng gần trăm vạn cấm chế phá vỡ tế đàn đá mới khiến nó lộ diện, sau đó phải vận Tê Thiên toàn lực mới phá nổi lớp hồng vân bảo hộ để thu lấy. Đây là phần thứ ba trong bộ ba phần tế đàn Phong Diệt Tộc: phần một là huyết các Huyết Tổ lấy được ở Côn Hư, phần hai là tế đàn lấy từ chỗ Cổ Yêu ở La Thiên, phần ba chính là vật bát giác này. Tập hợp đủ ba phần là điều kiện tiên quyết để tu luyện Tam Mệnh Thuật của Phong Diệt Tộc.","hinhDang":"Hình bát giác, tỏa hồng quang chói mắt, giống huyết trì","nguonGoc":"Phong Diệt Tộc, Thái Cổ Tinh Thần","congNang":["Phần thứ ba hoàn thiện bộ tế đàn Phong Diệt Tộc, gom đủ ba phần là điều kiện tu luyện Tam Mệnh Thuật @c1617"],"dacDiem":"Hình bát giác tỏa hồng quang chói mắt; hồng vân bảo hộ bên trong có thể tiêu diệt cấm chế như thiên địch; mang khí tức Phong Diệt Tộc từ Thái Cổ Tinh Thần","boCha":"tam-phan-te-dan-phong-diet-toc","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1617","denChuong":"","cachCoDuoc":"Phá vỡ tế đàn đá nơi cúng tế cánh tay Diệp Mịch, phát hiện và thu lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1617","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện khi Vương Lâm phá tế đàn đá","text":"Vương Lâm dùng gần trăm vạn cấm chế phá vỡ tế đàn đá, lộ ra vật bát giác tỏa hồng quang chói mắt mang khí tức Phong Diệt Tộc. Đây là phần tế đàn thứ ba và cuối cùng, gom đủ ba phần xác nhận cùng nguồn gốc.","anchor":"cuối cùng hiện ra trước mặt Vương Lâm rõ ràng là một vật bát giác, tỏa ra hồng quang chói mắt, giống như một huyết trì vậy"}]},"capNhatToi":"@c1617","nguon":["@c1617"]},{"id":"truong-dao-mau-tam-menh-thuat","name":"Trường đao máu (Tam Mệnh Thuật)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Tạm thời","soHuu":["Vương Lâm"],"trangThai":"da-mat","blurb":"Trường đao do máu tươi Vương Lâm biến thành khi thực hiện Tam Mệnh Thuật, thực tế là ba thanh đao chồng nhau. Chém xuyên thân thể trảm tam hồn nhưng tan nát do linh hồn Vương Lâm quá mạnh.","detail":"Khi thực hiện Tam Mệnh Thuật, Vương Lâm phun máu tươi niệm chú gọi tổ linh, máu hóa thành trường đao dài khoảng một trượng, thực tế là ba thanh đao chồng lên nhau trong hư ảo. Trường đao chém xuống đỉnh đầu xuyên qua toàn thân để thực hiện bước Trảm Tam Hồn. Chỉ máu chủ nhân mới chạm được linh hồn. Tuy nhiên linh hồn Vương Lâm (dung hợp hồn huyết Cổ Tổ) quá cường đại, đao chịu không nổi lực phản chấn — ba thanh chỉ còn hai rồi tan nát tiêu tán trong thiên địa.","congNang":["Trảm tam hồn khi chém xuyên thân thể"],"dacDiem":"Ba thanh đao chồng nhau trong hư ảo; chỉ máu chủ nhân mới chạm được linh hồn; tan nát khi linh hồn quá mạnh","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1617","denChuong":"@c1617","cachCoDuoc":"Máu tươi biến thành khi thực hiện Tam Mệnh Thuật","trangThai":"da-mat"}],"tabs":{"tienTrinh":[{"chuong":"@c1617","loai":"dùng","importance":"normal","giaiDoan":"Trảm Tam Hồn nhưng đao tan nát","text":"Trường đao máu chém xuyên thân thể Vương Lâm thực hiện Trảm Tam Hồn, trảm được tam hồn nhưng đao chịu không nổi lực phản chấn từ linh hồn quá mạnh, từ ba thanh còn hai rồi tan nát tiêu tán.","anchor":"đám máu tươi kia bất ngờ hóa thành hình dáng một thanh trường đao"}]},"capNhatToi":"@c1617","nguon":["@c1617"]},{"id":"thuy-bon-nguyen","name":"Thủy bổn nguyên (một tia)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không đủ bước thứ ba","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Giọt nước long lanh trong suốt chứa thủy bổn nguyên, Thiên Vận Tử trộm từ người khác năm xưa, chỉ có một tia, tặng cho Vương Lâm.","detail":"Thiên Vận Tử điểm vào mi tâm lấy ra giọt nước long lanh này, nói là thủy bổn nguyên trộm được từ người khác, chỉ có một tia không đủ để tiến vào bước thứ ba. Tặng cho Vương Lâm, lơ lửng trước mi tâm hắn, nếu Vương Lâm minh ngộ thủy bổn nguyên chính thức thì Thiên Vận Tử cũng được lợi.","congNang":["Gợi ý minh ngộ thủy bổn nguyên chính thức @c1625"],"chuSoHuu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1625","denChuong":"@c1625","cachCoDuoc":"Trộm từ người khác năm xưa","trangThai":"da-tang"},{"ten":"Vương Lâm","tuChuong":"@c1625","denChuong":"","cachCoDuoc":"Thiên Vận Tử tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1625","loai":"đổi chủ","importance":"normal","giaiDoan":"Thiên Vận Tử tặng cho Vương Lâm","text":"Thiên Vận Tử lấy từ mi tâm tặng cho Vương Lâm, nói nếu Vương Lâm minh ngộ thủy bổn nguyên chính thức thì hắn cũng cảm tạ.","anchor":"Đây là thủy bổn nguyên năm xưa vi sư đạt được trên người kẻ khác"}]},"nguon":["@c1625"]},{"id":"tho-bon-nguyen","name":"Thổ bổn nguyên (đám bùn đất)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đám bùn đất sống không ngừng nhúc nhích biến đổi hình dạng, chứa thổ bổn nguyên, Thiên Vận Tử vung tay trao cho Vương Lâm.","detail":"Đám bùn đất xuất hiện trong lòng bàn tay Thiên Vận Tử, giống vật sống, không ngừng biến đổi hình dạng. Thiên Vận Tử vung tay trao cho Vương Lâm cùng với thủy bổn nguyên.","chuSoHuu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1625","denChuong":"@c1625","cachCoDuoc":"","trangThai":"da-tang"},{"ten":"Vương Lâm","tuChuong":"@c1625","denChuong":"","cachCoDuoc":"Thiên Vận Tử tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1625","loai":"đổi chủ","importance":"normal","giaiDoan":"Thiên Vận Tử trao cho Vương Lâm","text":"Thiên Vận Tử vung tay đưa đám bùn đất nhúc nhích trao cho Vương Lâm cùng lúc đề xuất trò chơi.","anchor":"một đám bùn đất xuất hiện trong lòng bàn tay hắn"}]},"nguon":["@c1625"]},{"id":"nua-nghich-la-ban","name":"Nửa nghịch la bàn","aliases":["Nửa cái la bàn","Nửa la bàn"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Không rõ","soHuu":["Thiên Vận Tử"],"trangThai":"an-giau","blurb":"Nửa nghịch la bàn là bổn tôn thật sự của Thiên Đạo (Thiên Vận Tử), có hình dạng nửa vòng tròn mang ấn ký cổ xưa, khí tức đặc thù không ai có thể cảm nhận được. Vật này vốn nằm bên trong một cánh cửa khổng lồ khác cánh cửa Thiên Nghịch, khi cửa bị oanh kích vỡ tung liền bay ra cùng đám sương mù bạc và được cất giấu tại một tu chân tinh không có sinh mạng.","detail":"Nửa nghịch la bàn là bổn tôn của Thiên Đạo, tức Thiên Vận Tử. Vật này có hình dạng nửa vòng tròn, trên bề mặt khắc ấn ký cổ xưa giống la bàn, mang khí tức đặc thù mà không ai có thể cảm nhận được. Nửa nghịch la bàn vốn nằm bên trong một cánh cửa khổng lồ hòa hợp với tinh không, khác biệt với cánh cửa Thiên Nghịch. Khi cánh cửa này bị lực lượng cường đại từ bên trong oanh kích vỡ tung, đám sương mù bạc hình cầu chui ra và chia thành hai phần: phần lớn chứa bóng tiên nhân gào thét, bay xa rồi biến mất; phần nhỏ chứa nửa nghịch la bàn. Đám sương mù ngưng tụ trên nửa la bàn hóa thành cầu vồng, mang theo vật này bay vào một tu chân tinh không có sinh mạng, xuyên qua ngọn núi rồi chìm sâu vào bên trong. Thiên Đạo hóa hình thanh niên tuyên bố bổn tôn chính là nửa nghịch la bàn, khẳng định để ở nơ","hinhDang":"Nửa vòng tròn mang ấn ký cổ xưa giống la bàn","nguonGoc":"Vốn nằm trong cánh cửa khổng lồ (khác cánh cửa Thiên Nghịch), khi cánh cửa vỡ tung bay ra cùng đám sương mù bạc","dacDiem":"Hình dạng nửa vòng tròn mang ấn ký cổ xưa giống la bàn, khí tức đặc thù không ai có thể cảm nhận được.","chuHienThoi":"Thiên Vận Tử","congNang":["Là bổn tôn thật sự của Thiên Đạo / Thiên Vận Tử @c1628"],"chuSoHuu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1628","denChuong":"","cachCoDuoc":"Bổn tôn của chính hắn","trangThai":"an-giau"}],"tabs":{"tienTrinh":[{"chuong":"@c1628","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ bổn tôn Thiên Đạo","text":"Cánh cửa khổng lồ vỡ tung, đám sương mù bạc chia hai, phần nhỏ chứa nửa nghịch la bàn (bổn tôn Thiên Đạo) rơi vào tu chân tinh không sinh mạng, chìm sâu trong ngọn núi. Thiên đạo hóa hình thanh niên tuyên bố đây là bổn tôn của hắn. Vương Lâm ghi nhớ khí tức nơi cất giấu.","anchor":"Bổn tôn của ta chính là một nửa nghịch la bàn này"}]},"capNhatToi":"@c1628","nguon":["@c1628"]},{"id":"ho-lo-xanh-biec-co-xua","name":"Hồ lô xanh biếc cổ xưa","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tứ đại chiến tướng"],"trangThai":"dang-co","blurb":"Hồ lô khổng lồ màu xanh biếc cổ xưa do tứ đại chiến tướng viễn cổ tiên vực ngưng tụ thần thức biến ảo ra, dùng để dẫn lộ truy tìm mục tiêu.","detail":"Xuất hiện trên đỉnh đầu bốn chiến tướng, miệng hồ lô có đám thanh khí bị hút về phương xa. Bốn người mỗi khoảng dừng lại vái hồ lô và dùng thần niệm giao tiếp với nó, có vẻ dẫn đường tìm kiếm thứ gì đó trong Triệu Hà tinh vực.","hinhDang":"Khổng lồ, màu xanh biếc, cổ xưa","congNang":["Dẫn lộ/truy tìm bằng thanh khí bị hút về phương xa"],"chuSoHuu":[{"ten":"Tứ đại chiến tướng","tuChuong":"@c1631","denChuong":"","cachCoDuoc":"Ngưng tụ thần thức biến ảo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1631","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện dẫn lộ tại Triệu Hà tinh vực","text":"Tứ đại chiến tướng ngưng tụ thần thức biến ảo ra hồ lô khổng lồ xanh biếc trên đỉnh đầu, miệng hồ lô có thanh khí hút về phương xa, dùng thần niệm giao tiếp dẫn đường.","anchor":"trên đỉnh đầu bốn người đi đầu bất ngờ có một cái hồ lô khổng lồ biến ảo ra"}]},"nguon":["@c1631"]},{"id":"ho-lo-khong-lo-tu-dai-chien-tuong","name":"Hồ lô khổng lồ (tứ đại chiến tướng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thanh Long","Bạch Hổ","Huyền Vũ","Chu Tước"],"trangThai":"dang-co","blurb":"Pháp bảo hồ lô khổng lồ trôi trên đầu tứ đại chiến tướng, mơ hồ tỏa tiên khí, trông rất bất phàm.","detail":"Hồ lô khổng lồ trôi trên đầu tứ đại chiến tướng khi chặn đường Vương Lâm, mơ hồ tỏa tiên khí bất phàm. Công năng chưa rõ, được Vương Lâm lưu ý khi quan sát đối phương.","congNang":[],"chuSoHuu":[{"ten":"Tứ đại chiến tướng","tuChuong":"@c1632","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1632","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện trên đầu tứ đại chiến tướng","text":"Hồ lô khổng lồ trôi trên đầu tứ đại chiến tướng khi bao vây Vương Lâm, mơ hồ tỏa tiên khí bất phàm, được Vương Lâm lưu ý.","anchor":"Vương Lâm liền lưu ý một cái hồ lô khổng lồ trôi trên đầu tứ đại chiến tướng"}]},"nguon":["@c1632"]}]};
